import { Route, Routes } from "react-router-dom";
import { Suspense, lazy } from "react";
const Dashboard = lazy(() => import("./pages/Dashboard/temp"));
function Routers() {
  return (
    <div className="main-app">
      <Suspense fallback={<></>}>
        <Routes>
          <Route path="/" element={<Dashboard />} />
        </Routes>
      </Suspense>
    </div>
  );
}

export default Routers;
